// src/components/FuelPriceWidget.jsx
import React, { useState, useEffect } from 'react';
import './FuelPriceWidget.css';

// ─── RapidAPI config ──────────────────────────────────────────────────
const RAPID_API_URL     = 'https://daily-fuel-prices-update-india.p.rapidapi.com/car/v2/fuel/cities';
const RAPID_API_KEY     = '32cf5737e2msh7b20ac2ddd36c99p1c4c91jsnc099cd7dcb1a';
const RAPID_API_HOST    = 'daily-fuel-prices-update-india.p.rapidapi.com';

// ─── Cities we care about ────────────────────────────────────────────
// apiMatch: possible strings the API may return for this city name
const CITIES = [
  { label: 'Delhi',     apiMatch: ['delhi', 'new delhi'] },
  { label: 'Faridabad', apiMatch: ['faridabad'] },
  { label: 'Gurugram',  apiMatch: ['gurugram', 'gurgaon'] },
  { label: 'Noida',     apiMatch: ['noida'] },
  { label: 'Lucknow',   apiMatch: ['lucknow'] },
  { label: 'Jaipur',    apiMatch: ['jaipur'] },
];

const FUELS = [
  { key: 'Diesel', icon: '🛢️', color: '#16a34a', bg: '#f0fdf4' },
  { key: 'Petrol', icon: '⛽', color: '#f97316', bg: '#fff7ed' },
];

// ─── Parse RapidAPI response flexibly ────────────────────────────────
// Tries multiple key names the API might use
function parsePrice(obj, type) {
  // type = 'petrol' | 'diesel'
  const keys = type === 'petrol'
    ? ['petrol', 'petrol_price', 'petrolPrice', 'petrolprice', 'p_price']
    : ['diesel', 'diesel_price', 'dieselPrice', 'dieselprice', 'd_price'];
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null) {
      const n = parseFloat(v);
      if (!isNaN(n) && n > 50) return n; // sanity: price must be > ₹50
    }
  }
  return null;
}

function parseCityName(obj) {
  return (
    obj?.city_name || obj?.city || obj?.cityName ||
    obj?.City || obj?.name || ''
  ).toLowerCase().trim();
}

// ─── Fetch ALL cities once, cache result in module scope ─────────────
let _cache = null;
let _cacheFetching = false;
let _cacheCallbacks = [];

function fetchAllCities() {
  return new Promise((resolve) => {
    if (_cache) { resolve(_cache); return; }
    _cacheCallbacks.push(resolve);
    if (_cacheFetching) return;
    _cacheFetching = true;

    fetch(RAPID_API_URL, {
      method: 'GET',
      headers: {
        'x-rapidapi-key':  RAPID_API_KEY,
        'x-rapidapi-host': RAPID_API_HOST,
        'Content-Type':    'application/json',
        src:               'android-app',
        appVersion:        '1.0',
        deviceId:          'abcs',
      },
    })
      .then(r => r.json())
      .then(raw => {
        // Raw might be: array, { data: [...] }, { result: [...] }, { cities: [...] }
        const list = Array.isArray(raw)
          ? raw
          : Array.isArray(raw?.data)   ? raw.data
          : Array.isArray(raw?.result) ? raw.result
          : Array.isArray(raw?.cities) ? raw.cities
          : [];

        console.log('[FuelPriceWidget] API sample:', list[0]); // dev debug
        _cache = list;
        _cacheCallbacks.forEach(cb => cb(list));
        _cacheCallbacks = [];
      })
      .catch(err => {
        console.warn('[FuelPriceWidget] API error:', err);
        _cache = [];
        _cacheCallbacks.forEach(cb => cb([]));
        _cacheCallbacks = [];
      });
  });
}

// ─── Find city entry from API list ───────────────────────────────────
function findCityEntry(list, cityDef) {
  return list.find(item => {
    const name = parseCityName(item);
    return cityDef.apiMatch.some(m => name === m || name.includes(m));
  }) || null;
}

// ─── Date helpers ────────────────────────────────────────────────────
function todayStr() {
  return new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
}
function twoDaysAgoStr() {
  const d = new Date(); d.setDate(d.getDate() - 2);
  return d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
}

// ─── Component ───────────────────────────────────────────────────────
export default function FuelPriceWidget() {
  const [cityDef, setCityDef] = useState(CITIES[0]);
  const [prices, setPrices]   = useState(null);
  const [prevPrices, setPrev] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isLive, setIsLive]   = useState(false);
  const [lastUpdated, setLastUpdated] = useState('');

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setPrices(null);

    fetchAllCities().then(list => {
      if (cancelled) return;

      const entry = findCityEntry(list, cityDef);
      let todayData = null;

      if (entry) {
        const petrol = parsePrice(entry, 'petrol');
        const diesel = parsePrice(entry, 'diesel');
        if (petrol && diesel) {
          todayData = { Petrol: petrol, Diesel: diesel };
          setIsLive(true);
        }
      }

      if (!todayData) {
        // Should rarely happen — if API worked but city not found or bad parse
        // show error state, not fake static prices
        setIsLive(false);
        todayData = null;
      }

      // Previous price: API sometimes has prev_price / yesterday_price field
      const prevPetrol = entry
        ? (parsePrice(entry, 'petrol') // some APIs have prev_petrol_price etc
            ?? parsePrice({ ...entry,
                petrol:        entry?.prev_petrol_price ?? entry?.petrol,
                petrol_price:  entry?.prev_petrol_price ?? entry?.petrol_price,
               }, 'petrol'))
        : null;
      const prevDiesel = entry
        ? (parsePrice({
                diesel:        entry?.prev_diesel_price ?? entry?.diesel,
                diesel_price:  entry?.prev_diesel_price ?? entry?.diesel_price,
               }, 'diesel'))
        : null;

      // Only show prev if it differs from today (some APIs give a yesterday field)
      const prevData = (prevPetrol && prevDiesel && todayData)
        ? { Petrol: prevPetrol, Diesel: prevDiesel }
        : null;

      setPrices(todayData);
      setPrev(prevData);
      setLastUpdated(todayStr());
      setLoading(false);
    });

    return () => { cancelled = true; };
  }, [cityDef]);

  const trend = (fuel) => {
    if (!prices || !prevPrices) return null;
    const d = parseFloat((prices[fuel] - prevPrices[fuel]).toFixed(2));
    if (d > 0.009)  return { color: '#ef4444', arrow: '↑', label: `+₹${d.toFixed(2)}` };
    if (d < -0.009) return { color: '#16a34a', arrow: '↓', label: `-₹${Math.abs(d).toFixed(2)}` };
    return { color: '#6b7280', arrow: '→', label: 'No change' };
  };

  return (
    <div className="fpw-root">

      {/* ── Header ── */}
      <div className="fpw-header">
        <div className="fpw-header-left">
          <span className="fpw-live-dot" />
          <span className="fpw-title">Live Fuel Prices</span>
          {lastUpdated && (
            <span className="fpw-updated">
              {isLive ? '🟢 Live · ' : '⚠️ '}
              {lastUpdated}
            </span>
          )}
        </div>
        <select
          className="fpw-city-select"
          value={cityDef.label}
          onChange={e => setCityDef(CITIES.find(c => c.label === e.target.value))}
        >
          {CITIES.map(c => <option key={c.label}>{c.label}</option>)}
        </select>
      </div>

      {/* ── Body ── */}
      <div className="fpw-body">
        {loading && (
          <div className="fpw-loading">
            <span className="fpw-spinner" />
            <span>Fetching live prices…</span>
          </div>
        )}

        {!loading && !prices && (
          <div className="fpw-loading" style={{ color: '#ef4444' }}>
            ⚠️ Could not load prices. Please try again later.
          </div>
        )}

        {!loading && prices && FUELS.map(f => {
          const t = trend(f.key);
          return (
            <div key={f.key} className="fpw-row" style={{ '--fc': f.color, '--fb': f.bg }}>

              <div className="fpw-row-left">
                <span className="fpw-row-icon">{f.icon}</span>
                <span className="fpw-row-name">{f.key}</span>
              </div>

              <div className="fpw-today">
                <span className="fpw-today-label">Today</span>
                <span className="fpw-today-price">₹{prices[f.key].toFixed(2)}</span>
                <span className="fpw-today-unit">/ litre</span>
              </div>

              {prevPrices && (
                <>
                  <div className="fpw-divider" />
                  <div className="fpw-past">
                    <span className="fpw-past-label">{twoDaysAgoStr()}</span>
                    <span className="fpw-past-price">₹{prevPrices[f.key].toFixed(2)}</span>
                  </div>
                </>
              )}

              {t && (
                <div className="fpw-badge" style={{ background: t.color + '18', color: t.color }}>
                  <span className="fpw-badge-arrow">{t.arrow}</span>
                  <span className="fpw-badge-val">{t.label}</span>
                </div>
              )}

            </div>
          );
        })}
      </div>

      {/* ── Footer ── */}
      <div className="fpw-footer">
        {prices ? (
          <span>📍 Prices for <strong>{cityDef.label}</strong> · Incl. VAT &amp; local levies</span>
        ) : (
          !loading && <span style={{ color: '#ef4444' }}>Price data unavailable for {cityDef.label}</span>
        )}
      </div>

    </div>
  );
}
